import{_ as a,c as r,m as e,a as o,t as i,U as s,o as n}from"./chunks/framework.9QHaLlVJ.js";const f=JSON.parse('{"title":"1xx","description":"","frontmatter":{"title":"1xx"},"headers":[],"relativePath":"doc/网络协议/HTTP/状态码/1xx.md","filePath":"packages/doc/src/网络协议/HTTP/状态码/1xx.md","lastUpdated":1704643216000}'),c={name:"doc/网络协议/HTTP/状态码/1xx.md"},l={id:"frontmatter-title",tabindex:"-1"},h=e("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),p=s('<p>这一类型的状态码，代表请求已被接受，需要继续处理。有以下特性：</p><ul><li>这类响应是<strong>临时响应</strong>，只包含状态行和某些可选的响应头信息，并以空行结束。</li><li>由于HTTP/1.0协议中没有定义任何1xx状态码，所以除非在某些试验条件下，服务器<strong>禁止</strong>向此类客户端发送1xx响应。</li><li>这些状态码代表的响应都是<strong>信息性</strong>的，标示客户应该等待服务器采取进一步行动。</li></ul><h3 id="_100-continue" tabindex="-1">100 Continue <a class="header-anchor" href="#_100-continue" aria-label="Permalink to &quot;100 Continue&quot;">​</a></h3><p>服务器已经接收到请求头，并且<a href="https://www.zhihu.com/search?q=%E5%AE%A2%E6%88%B7%E7%AB%AF&amp;search_source=Entity&amp;hybrid_search_source=Entity&amp;hybrid_search_extra=%7B%22sourceType%22%3A%22article%22%2C%22sourceId%22%3A396387142%7D" target="_blank" rel="noreferrer">客户端</a>应继续发送请求主体（在需要发送身体的请求的情况下：例如，POST请求），或者如果请求已经完成，忽略这个响应。</p><p>服务器必须在请求完成后向客户端发送一个最终响应。</p><p>要使服务器检查请求的头部，客户端必须在其初始请求中发送 <code>Expect: 100-continue</code> 作为头部，并在发送正文之前接收<code>100 Continue</code>状态代码。</p><h3 id="_101-switching-protocols-协议升级-websocket" tabindex="-1">101 Switching Protocols 协议升级，websocket <a class="header-anchor" href="#_101-switching-protocols-协议升级-websocket" aria-label="Permalink to &quot;101 Switching Protocols 协议升级，websocket&quot;">​</a></h3><p>服务器已经理解了客户端的请求，并将通过Upgrade消息头通知客户端采用不同的协议来完成这个请求。在发送完这个响应最后的空行后，服务器将会切换到在Upgrade消息头中定义的那些协议。</p><p>只有在切换新的协议更有好处的时候才应该采取类似措施。例如，切换到新的HTTP版本（如<a href="https://link.zhihu.com/?target=https%3A//zh.wikipedia.org/wiki/HTTP/2" target="_blank" rel="noreferrer">HTTP/2</a>）比旧版本更有优势，或者切换到一个实时且同步的协议（如<a href="https://link.zhihu.com/?target=https%3A//zh.wikipedia.org/wiki/WebSocket" target="_blank" rel="noreferrer">WebSocket</a>）以传送利用此类特性的资源。</p><h3 id="_102-processing" tabindex="-1">102 Processing <a class="header-anchor" href="#_102-processing" aria-label="Permalink to &quot;102 Processing&quot;">​</a></h3><p>WebDAV请求可能包含许多涉及文件操作的子请求，需要很长时间才能完成请求。该代码表示服务器已经收到并正在处理请求，但无响应可用。这样可以防止客户端超时，并假设请求丢失。</p><h3 id="_103-early-hints" tabindex="-1">103 Early Hints <a class="header-anchor" href="#_103-early-hints" aria-label="Permalink to &quot;103 Early Hints&quot;">​</a></h3><p>用来在最终的HTTP消息之前返回一些响应头。</p>',13);function d(t,_,u,g,x,m){return n(),r("div",null,[e("h1",l,[o(i(t.$frontmatter.title)+" ",1),h]),p])}const k=a(c,[["render",d]]);export{f as __pageData,k as default};
